#include<bits/stdc++.h>
using namespace std;
string a;
long long n, len;
char dfs(long long w, long long len) {
	if (len == a.size() - 1) {
		return a[w];
	} else {
		if (w > len / 2) {
			if (w - len / 2 != 1) return dfs(w - 1 - len / 2, len / 2);
			else return dfs(len / w, len /2);
		} else {
			return dfs(w, len / 2);
		}
	}
}
int main() {
	cin >> a >> n;
	a = ' ' + a;
	len = a.size() - 1;
	while (len < n) len *= 2;
	cout << dfs(n, len);
	return 0;
}
